from dataclasses import dataclass
from typing import Literal

InterestWeight = {"critical": 4.0, "high": 2.5, "medium": 1.5, "low": 0.5}

@dataclass
class CODIScore:
    """
    CODI = (Impact x Interest) / Effort

    Impact: 0-100 score reflecting reach and severity of the debt item
    Interest rate: categorical weight (critical=4.0, high=2.5, medium=1.5, low=0.5)
    Effort: engineering-days to resolve
    """
    impact: float              # 0-100: user reach × severity multiplier
    interest_rate: Literal["critical", "high", "medium", "low"]
    effort_days: float

    @property
    def score(self) -> float:
        weight = InterestWeight[self.interest_rate]
        return round((self.impact * weight) / max(self.effort_days, 0.5), 1)

    @property
    def quadrant(self) -> str:
        mid_impact = 50
        mid_effort = 4.0
        if self.impact >= mid_impact and self.effort_days < mid_effort:
            return "quick-win"
        if self.impact >= mid_impact and self.effort_days >= mid_effort:
            return "big-bet"
        if self.impact < mid_impact and self.effort_days < mid_effort:
            return "small-win"
        return "icebox"

# Example: API key exposure vs. chunk strategy evaluation
api_key = CODIScore(impact=95, interest_rate="critical", effort_days=1.0)
chunk_strategy = CODIScore(impact=55, interest_rate="medium", effort_days=8.0)

print(f"API key: CODI={api_key.score}, quadrant={api_key.quadrant}")
print(f"Chunk strategy: CODI={chunk_strategy.score}, quadrant={chunk_strategy.quadrant}")
# API key: CODI=380.0, quadrant=quick-win
# Chunk strategy: CODI=10.3, quadrant=big-bet

from dataclasses import dataclass, field

@dataclass
class EffortEstimate:
    implementation_days: float
    eval_run_days: float = 0.0       # any change touching prompt/model/RAG
    review_days: float = 0.0         # security review, safety review, etc.
    deploy_days: float = 0.0         # canary, monitoring period, rollback check
    integration_days: float = 0.0   # updating downstream consumers

    @property
    def total_days(self) -> float:
        return (
            self.implementation_days
            + self.eval_run_days
            + self.review_days
            + self.deploy_days
            + self.integration_days
        )

estimates = {
    "TD-038 hardcoded date": EffortEstimate(
        implementation_days=0.25,
        eval_run_days=0.5,    # need to run eval to confirm no regression
        deploy_days=0.25,
    ),  # total: 1.0d

    "TD-039 eval gap": EffortEstimate(
        implementation_days=2.0,   # write 50 cases with ground truth
        review_days=1.0,           # QA review of case quality
        integration_days=0.5,      # CI pipeline integration
        deploy_days=0.0,           # no deploy needed
    ),  # total: 3.5d

    "TD-040 stale RAG index": EffortEstimate(
        implementation_days=1.5,   # add TTL + eviction logic
        eval_run_days=1.5,         # verify retrieval quality unchanged
        deploy_days=1.0,           # canary + watch metrics
    ),  # total: 4.0d
}

for name, est in estimates.items():
    print(f"{name}: {est.total_days:.1f} days total")
